/**
 * Disjoint Set Union (DSU) structure optimized for path compression and union by rank/size.
 * In this specific problem, we need to maintain the parity of path weights (XOR sum)
 * from each node to its set representative.
 */
class DSU {
    constructor(n) {
        this.parent = new Array(n).fill(0).map((_, i) => i);
        // parity[i] stores the XOR sum of edge weights on the path from i to parent[i].
        // 0 means even path weight, 1 means odd path weight.
        this.parity = new Array(n).fill(0);
    }

    /**
     * Finds the representative (root) of the set containing i, and updates parity.
     * @param {number} i The node index.
     * @returns {number} The root of the set.
     */
    find(i) {
        if (this.parent[i] === i) {
            return i;
        }

        // Recursively find the root and perform path compression
        const root = this.find(this.parent[i]);

        // Update the parity of i: 
        // The new path from i to root is (path i -> old_parent) XOR (path old_parent -> root).
        // path i -> old_parent is stored in this.parity[i].
        // path old_parent -> root is the updated value of this.parity[this.parent[i]].
        this.parity[i] = this.parity[i] ^ this.parity[this.parent[i]];

        this.parent[i] = root;
        return root;
    }

    /**
     * Unites the sets containing u and v, given the weight of the edge (u, v).
     * @param {number} u Node u.
     * @param {number} v Node v.
     * @param {number} w Edge weight (0 or 1).
     * @returns {boolean} True if a union was performed (i.e., u and v were in different sets), false otherwise.
     */
    union(u, v, w) {
        const rootU = this.find(u);
        const rootV = this.find(v);

        if (rootU !== rootV) {
            // Merge V's set into U's set (arbitrary choice)
            this.parent[rootV] = rootU;

            // We need to determine the new parity for rootV relative to its new parent rootU.
            // Let P(x) be the parity from x to its root.
            // We have:
            // 1. P(u) = parity[u] (path u -> rootU)
            // 2. P(v) = parity[v] (path v -> rootV)
            // 3. The new edge weight is w.
            // We want to set parity[rootV] such that the path rootV -> u -> v -> rootU has the correct parity.
            // The path from rootV to rootU goes through the new edge (v, u) with weight w.
            // Parity(rootV -> rootU) = Parity(rootV -> v) XOR w XOR Parity(u -> rootU)
            // Parity(rootV -> v) = P(v) (since v is now connected to rootV, its parity to rootV is 0, but we are setting parent[rootV]=rootU)

            // The path from rootV to rootU is: rootV --(parity[rootV])--> rootU.
            // We want the path from rootV to rootU via the edge (v, u) to have parity (P(v) ^ w ^ P(u)).
            // P(rootV -> rootU) = P(rootV -> v) ^ w ^ P(u -> rootU)
            // Since P(v) is the path parity from v to rootV, and we are setting parent[rootV] = rootU, 
            // we are essentially defining the path from rootV to rootU.

            // Path: rootV --(new edge path)--> rootU
            // This path is equivalent to: rootV --(P(v))--> v --(w)--> u --(P(u))--> rootU
            // The required parity for rootV -> rootU is P(v) ^ w ^ P(u).
            this.parity[rootV] = this.parity[u] ^ w ^ this.parity[v];

            return true;
        }
        return false;
    }
}


function solve(n, edges) {
    const dsu = new DSU(n);
    let addedEdgesCount = 0;

    for (const edge of edges) {
        const [u, v, w] = edge;

        // 1. Find representatives and path parities
        const rootU = dsu.find(u);
        const rootV = dsu.find(v);

        // 2. Check if adding the edge creates an odd cycle
        if (rootU === rootV) {
            // They are already connected. Adding the edge (u, v) creates a cycle.

            // Parity of path u -> v currently (through existing structure)
            // Path: u --(parity[u])--> rootU --(parity[v] XOR parity[u])--> v
            // Path parity P_uv = parity[u] XOR parity[v]

            // Cycle parity = P_uv XOR w
            // Cycle parity = parity[u] XOR parity[v] XOR w
            const cycleParity = dsu.parity[u] ^ dsu.parity[v] ^ w;

            // The edge is added only if the new cycle has an EVEN total weight (cycleParity == 0).
            if (cycleParity === 0) {
                // The condition is: "if adding it maintains that every cycle has even weight"
                // If the cycle parity is 0, it is even, so we add it.
                // However, if rootU === rootV, adding the edge *closes* a cycle.
                // If the cycle is even, we add it.
                // If the cycle is odd, we reject it.

                // WAIT: The problem statement implies that the *current* state must be such that
                // adding the edge does not create an odd cycle.
                // If rootU == rootV, the cycle parity check *is* the check for the new cycle.
                // If cycleParity == 0 (even), we add it.
                // If cycleParity == 1 (odd), we reject it.
                addedEdgesCount++;
                // Note: We don't need to modify DSU state because it's already connected.
            }
            // If cycleParity is 1, we skip adding the edge.
        } else {
            // They are in different components. Adding the edge cannot create a cycle.
            // Therefore, the condition "every cycle has even weight" is maintained trivially 
            // (since there are no new cycles, and existing cycles are already known to be even,
            // provided the DSU structure correctly maintains the property).

            // We union the sets and record the path parity relationship.
            dsu.union(u, v, w);
            addedEdgesCount++;
        }
    }

    return addedEdgesCount;
}

